  const content = document.createElement("div");
  content.className = `MapRoutePreview MapRoutePreview--normalHasArrow MapRoutePreview--${variant}`;
  content.innerHTML = `
    <svg class="MapRoutePreview__networkSvg" viewBox="0 0 282 121">
      <path class="MapRoutePreview__route MapRoutePreview__route--primary" d="..." />
      <g class="MapRoutePreview__arrows MapRoutePreview__arrows--primary">...</g>
    </svg>
  `;
  return content;
}

routeWithLocation.code:
type RouteLocationKind = "normal" | "informated";

function createRouteWithLocation(kind: RouteLocationKind, state: "default" | "muted" | "completed") {
  const family = kind === "normal" ? "routeWithNormalLocation" : "routeWithInformatedLocation";
  const content = document.createElement("div");
  content.className = `MapRoutePreview MapRoutePreview--${family} MapRoutePreview--${state}`;
  content.innerHTML = `
    <span class="MapRouteComposite MapRouteComposite--${family} MapRouteComposite--${state}">
      <span class="MapRoutePrimitive MapRoutePrimitive--${state}">...</span>
      <span class="MapRouteComposite__point MapRouteComposite__point--start"></span>
      <span class="MapRouteComposite__point MapRouteComposite__point--end"></span>
    </span>
  `;
  return content;
}

